  1→"use client";
  2→
  3→import { useState } from "react";
  4→import {
  5→  Dialog,
  6→  DialogContent,
  7→  DialogHeader,
  8→  DialogTitle,
  9→  DialogDescription,
 10→  DialogFooter,
 11→} from "@/components/ui/dialog";
 12→import { Button } from "@/components/ui/button";
 13→import { ToggleGroup, ToggleGroupItem } from "@/components/ui/toggle-group";
 14→import { useLocale } from "@/lib/i18n/useLocale";
 15→import { parseMermaid } from "@/lib/mermaid/parse";
 16→import { useFlowStore } from "@/store/useFlowStore";
 17→import { toast } from "sonner";
 18→import type { EdgeType } from "@/types/flow";
 19→
 20→const EDGE_TYPE_STORAGE_KEY = "flowmaid-mermaid-edge-type";
 21→
 22→function getStoredEdgeType(): EdgeType {
 23→  if (typeof window === "undefined") return "bezier";
 24→  const stored = localStorage.getItem(EDGE_TYPE_STORAGE_KEY);
 25→  if (stored === "bezier" || stored === "straight" || stored === "step") return stored;
 26→  return "bezier";
 27→}
 28→
 29→interface MermaidImportDialogProps {
 30→  open: boolean;
 31→  onOpenChange: (open: boolean) => void;
 32→  onSuccess?: () => void;
 33→}
 34→
 35→export function MermaidImportDialog({
 36→  open,
 37→  onOpenChange,
 38→  onSuccess,
 39→}: MermaidImportDialogProps) {
 40→  const [text, setText] = useState("");
 41→  const [edgeType, setEdgeType] = useState<EdgeType>(getStoredEdgeType);
 42→  const { t } = useLocale();
 43→  const loadState = useFlowStore((s) => s.loadState);
 44→  const hasContent = useFlowStore((s) => s.nodes.length > 0 || s.edges.length > 0);
 45→
 46→  const handleEdgeTypeChange = (value: string) => {
 47→    if (!value) return;
 48→    const et = value as EdgeType;
 49→    setEdgeType(et);
 50→    localStorage.setItem(EDGE_TYPE_STORAGE_KEY, et);
 51→  };
 52→
 53→  const doConvert = () => {
 54→    try {
 55→      const result = parseMermaid(text, edgeType);
 56→      loadState(result);
 57→      toast.success(t("mermaidImportSuccess"));
 58→      setText("");
 59→      onOpenChange(false);
 60→      onSuccess?.();
 61→    } catch {
 62→      toast.error(t("mermaidParseFailed"));
 63→    }
 64→  };
 65→
 66→  const handleConvert = () => {
 67→    if (hasContent) {
 68→      if (!window.confirm(t("mermaidOverwriteConfirm"))) return;
 69→    }
 70→    doConvert();
 71→  };
 72→
 73→  return (
 74→    <Dialog open={open} onOpenChange={onOpenChange}>
 75→      <DialogContent>
 76→        <DialogHeader>
 77→          <DialogTitle>{t("importMermaid")}</DialogTitle>
 78→          <DialogDescription>{t("mermaidImportDesc")}</DialogDescription>
 79→        </DialogHeader>
 80→        <div className="flex items-center gap-2">
 81→          <span className="text-sm text-muted-foreground">{t("edgeTypeLabel")}:</span>
 82→          <ToggleGroup
 83→            type="single"
 84→            value={edgeType}
 85→            onValueChange={handleEdgeTypeChange}
 86→          >
 87→            <ToggleGroupItem value="bezier" className="h-8 px-2 text-xs">
 88→              {t("bezier")}
 89→            </ToggleGroupItem>
 90→            <ToggleGroupItem value="straight" className="h-8 px-2 text-xs">
 91→              {t("straight")}
 92→            </ToggleGroupItem>
 93→            <ToggleGroupItem value="step" className="h-8 px-2 text-xs">
 94→              {t("step")}
 95→            </ToggleGroupItem>
 96→          </ToggleGroup>
 97→        </div>
 98→        <textarea
 99→          className="w-full h-48 rounded-md border border-input bg-background px-3 py-2 text-sm font-mono resize-none focus:outline-none focus:ring-2 focus:ring-ring"
100→          value={text}
101→          onChange={(e) => setText(e.target.value)}
102→          placeholder={"graph TD\n    A[Start] --> B{Condition}\n    B -->|Yes| C[End]"}
103→        />
104→        <DialogFooter>
105→          <Button onClick={handleConvert} disabled={!text.trim()}>
106→            {t("convert")}
107→          </Button>
108→        </DialogFooter>
109→      </DialogContent>
110→    </Dialog>
111→  );
112→}
