 1→import { create } from "zustand";
 2→import { locales, type Locale, type TranslationKey } from "./locales";
 3→
 4→const LOCALE_STORAGE_KEY = "flowmaid-locale";
 5→
 6→function detectLocale(): Locale {
 7→  if (typeof window === "undefined") return "en";
 8→  const saved = localStorage.getItem(LOCALE_STORAGE_KEY);
 9→  if (saved === "ja" || saved === "en") return saved;
10→  const lang = navigator.language;
11→  return lang.startsWith("ja") ? "ja" : "en";
12→}
13→
14→interface LocaleState {
15→  locale: Locale;
16→  setLocale: (locale: Locale) => void;
17→}
18→
19→export const useLocaleStore = create<LocaleState>()((set) => ({
20→  locale: "en",
21→  setLocale: (locale: Locale) => {
22→    localStorage.setItem(LOCALE_STORAGE_KEY, locale);
23→    set({ locale });
24→  },
25→}));
26→
27→// Hydrate on client side
28→if (typeof window !== "undefined") {
29→  useLocaleStore.setState({ locale: detectLocale() });
30→}
31→
32→/** Hook that returns { locale, setLocale, t } — re-renders when locale changes */
33→export function useLocale() {
34→  const locale = useLocaleStore((s) => s.locale);
35→  const setLocale = useLocaleStore((s) => s.setLocale);
36→  const t = (key: TranslationKey) => locales[locale][key];
37→  return { locale, setLocale, t };
38→}
