 38→/** Resizable handle with click-to-toggle. Drag = resize, click = collapse panel.
 39→ *  Design matches PanelRibbon (w-6, bg-muted/50, border-x, chevron + vertical label). */
 40→function ToggleResizeHandle({ onClick }: { onClick: () => void }) {
 41→  const draggedRef = useRef(false);
 42→  return (
 43→    <div
 44→      className="relative shrink-0 flex flex-col items-center justify-center gap-1 bg-muted/50 hover:bg-muted border-x border-border cursor-pointer transition-colors"
 45→      style={{ width: 24 }}
 46→      onPointerDown={() => { draggedRef.current = false; }}
 47→      onPointerMove={() => { draggedRef.current = true; }}
 48→      onPointerUp={() => {
 49→        if (!draggedRef.current) onClick();
 50→      }}
 51→    >
 52→      <ResizableHandle bare className="absolute inset-0 z-10 cursor-pointer" />
 53→      <ChevronRight size={14} className="text-muted-foreground" />
 54→      <span
 55→        className="text-[10px] text-muted-foreground"
 56→        style={{ writingMode: "vertical-rl", textOrientation: "mixed" }}
 57→      >
 58→        Output
 59→      </span>
 60→    </div>
 61→  );
 62→}
 63→
 64→/** Thin ribbon shown when panel is collapsed. Click to expand. Matches PanelRibbon design. */
 65→function ToggleRibbon({ onClick }: { onClick: () => void }) {
 66→  return (
 67→    <button
 68→      onClick={onClick}
 69→      className="shrink-0 flex flex-col items-center justify-center w-6 h-full bg-muted/50 hover:bg-muted border-x border-border cursor-pointer transition-colors"
 70→    >
 71→      <ChevronLeft size={14} className="text-muted-foreground" />
 72→      <span
 73→        className="text-[10px] text-muted-foreground"
 74→        style={{ writingMode: "vertical-rl", textOrientation: "mixed" }}
 75→      >
 76→        Output
 77→      </span>
 78→    </button>
 79→  );
 80→}
