 82→export function EditorLayout() {
 83→  perfCount("EditorLayout");
 84→  const { leftOpen, rightOpen, leftWidth, toggleLeft, toggleRight } =
 85→    usePanelState();
 86→  const fileInputRef = useRef<HTMLInputElement>(null);
 87→  const [mermaidImportOpen, setMermaidImportOpen] = useState(false);
 88→  const [isBulkEditMode, setIsBulkEditMode] = useState(false);
 89→  const [bulkEditFocusTarget, setBulkEditFocusTarget] = useState<{
 90→    type: "node" | "edge";
 91→    id: string;
 92→  } | null>(null);
 93→  const [bulkEditHighlightId, setBulkEditHighlightId] = useState<string | null>(null);
 94→  const [bulkEditSelectedIds, setBulkEditSelectedIds] = useState<string[]>([]);
 95→  const { t } = useLocale();
 96→  const isEditingComponent = useFlowStore((s) => !!s.editingComponentId);
 97→
 98→  useAutoSave();
 99→  useKeyboardShortcuts();
100→
101→  // Listen for export events
102→  useEffect(() => {
103→    const handleExportEvent = () => {
104→      const { nodes, edges, direction, componentDefinitions } = useFlowStore.getState();
105→      const content = serialize(nodes, edges, direction, componentDefinitions);
106→      const blob = new Blob([content], { type: "text/plain" });
107→      const url = URL.createObjectURL(blob);
108→      const a = document.createElement("a");
109→      a.href = url;
110→      a.download = "flowchart.flowmaid";
111→      a.click();
112→      URL.revokeObjectURL(url);
113→      toast.success(locales[useLocaleStore.getState().locale]["exportedSuccess"]);
114→    };
115→
116→    const handleImportEvent = (e: Event) => {
117→      try {
118→        const content = (e as CustomEvent).detail as string;
119→        const result = deserialize(content);
120→        useFlowStore.getState().loadState(result);
121→        toast.success(locales[useLocaleStore.getState().locale]["importedSuccess"]);
122→      } catch (err) {
123→        toast.error(locales[useLocaleStore.getState().locale]["importFailed"]);
124→        console.error(err);
125→      }
126→    };
127→
128→    window.addEventListener("flowmaid:export", handleExportEvent);
129→    window.addEventListener("flowmaid:import", handleImportEvent);
130→    return () => {
131→      window.removeEventListener("flowmaid:export", handleExportEvent);
132→      window.removeEventListener("flowmaid:import", handleImportEvent);
133→    };
134→  }, []);
135→
136→  const handleExport = useCallback(() => {
137→    window.dispatchEvent(new CustomEvent("flowmaid:export"));
138→  }, []);
139→
140→  const handleImport = useCallback(() => {
141→    fileInputRef.current?.click();
142→  }, []);
143→
144→  const handleFileChange = useCallback(
145→    (e: React.ChangeEvent<HTMLInputElement>) => {
146→      const file = e.target.files?.[0];
147→      if (!file) return;
148→      const reader = new FileReader();
149→      reader.onload = (ev) => {
150→        const content = ev.target?.result as string;
151→        window.dispatchEvent(
152→          new CustomEvent("flowmaid:import", { detail: content })
153→        );
154→      };
155→      reader.readAsText(file);
156→      e.target.value = "";
157→    },
158→    []
159→  );
160→
161→  const handleImportMermaid = useCallback(() => {
162→    setMermaidImportOpen(true);
163→  }, []);
164→
165→  const handleFitView = useCallback(() => {
166→    window.dispatchEvent(new CustomEvent("flowmaid:fitview"));
167→  }, []);
168→
169→  const handleEnterBulkEdit = useCallback(() => {
170→    setBulkEditFocusTarget(null);
171→    setBulkEditHighlightId(null);
172→    setBulkEditSelectedIds([]);
173→    setIsBulkEditMode(true);
174→  }, []);
175→
176→  const handleExitBulkEdit = useCallback(() => {
177→    setIsBulkEditMode(false);
178→    setBulkEditFocusTarget(null);
179→    setBulkEditHighlightId(null);
180→    setBulkEditSelectedIds([]);
181→  }, []);
182→
183→  // Table row click → highlight + zoom
184→  const handleBulkEditFocusNode = useCallback((nodeId: string) => {
185→    setBulkEditSelectedIds([]);
186→    setBulkEditFocusTarget({ type: "node", id: nodeId });
187→    setBulkEditHighlightId(nodeId);
188→  }, []);
189→
190→  const handleBulkEditFocusEdge = useCallback((edgeId: string) => {
191→    setBulkEditSelectedIds([]);
192→    setBulkEditFocusTarget({ type: "edge", id: edgeId });
193→    setBulkEditHighlightId(edgeId);
194→  }, []);
195→
196→  // Canvas click → highlight only (no zoom)
197→  const handleBulkEditCanvasNodeClick = useCallback((nodeId: string) => {
198→    setBulkEditSelectedIds([]);
199→    setBulkEditFocusTarget(null);
200→    setBulkEditHighlightId(nodeId);
201→  }, []);
202→
203→  const handleBulkEditCanvasEdgeClick = useCallback((edgeId: string) => {
204→    setBulkEditSelectedIds([]);
205→    setBulkEditFocusTarget(null);
206→    setBulkEditHighlightId(edgeId);
207→  }, []);
208→
209→  const handleBulkEditSelectionChange = useCallback((selectedIds: string[]) => {
210→    setBulkEditSelectedIds(selectedIds);
211→    if (selectedIds.length > 0) {
212→      setBulkEditHighlightId(null);
213→      setBulkEditFocusTarget(null);
214→    }
215→  }, []);
216→
217→  const handleBulkEditPaneClick = useCallback(() => {
218→    setBulkEditSelectedIds([]);
219→    setBulkEditHighlightId(null);
220→    setBulkEditFocusTarget(null);
221→  }, []);
222→
223→  return (
224→    <ReactFlowProvider>
225→      <DnDProvider>
226→        <div
227→          className="h-screen w-screen overflow-hidden flex flex-col transition-[padding,background-color] duration-500 ease-in-out"
228→          style={{
229→            padding: isEditingComponent ? '0.4% 1% 1% 1%' : '0',
230→            backgroundColor: isEditingComponent ? 'var(--foreground)' : 'transparent',
231→          }}
232→        >
233→          <div
234→            className="overflow-hidden transition-[max-height,opacity] duration-500 ease-in-out"
235→            style={{
236→              maxHeight: isEditingComponent ? '48px' : '0px',
237→              opacity: isEditingComponent ? 1 : 0,
238→            }}
239→          >
240→            <ComponentEditingHeader />
241→          </div>
242→          <div className={`flex-1 min-h-0 w-full flex flex-col transition-[border-radius] duration-500 ease-in-out overflow-hidden ${isEditingComponent ? 'rounded-lg bg-background' : ''}`}>
243→          <Toolbar
244→            onExport={isBulkEditMode ? undefined : handleExport}
245→            onImport={isBulkEditMode ? undefined : handleImport}
246→            onImportMermaid={isBulkEditMode ? undefined : handleImportMermaid}
247→            onFitView={isBulkEditMode ? undefined : handleFitView}
248→            isBulkEditMode={isBulkEditMode}
249→            onEnterBulkEdit={isEditingComponent ? undefined : handleEnterBulkEdit}
250→            onExitBulkEdit={handleExitBulkEdit}
251→          />
252→          {!isBulkEditMode && <FormatBar />}
253→          {isBulkEditMode ? (
254→            <div className="flex flex-1 overflow-hidden">
255→              <ResizablePanelGroup orientation="horizontal" className="flex-1">
256→                <ResizablePanel defaultSize={BULK_EDIT_CANVAS_DEFAULT_SIZE} minSize={BULK_EDIT_CANVAS_MIN_SIZE}>
257→                  <BulkEditCanvas
258→                    focusTarget={bulkEditFocusTarget}
259→                    highlightId={bulkEditHighlightId}
260→                    onNodeClick={handleBulkEditCanvasNodeClick}
261→                    onEdgeClick={handleBulkEditCanvasEdgeClick}
262→                    onSelectionChange={handleBulkEditSelectionChange}
263→                    onPaneClick={handleBulkEditPaneClick}
264→                    onExit={handleExitBulkEdit}
265→                  />
266→                </ResizablePanel>
267→                <ResizableHandle bare className="w-px bg-border" />
268→                <ResizablePanel defaultSize={BULK_EDIT_TABLE_DEFAULT_SIZE} minSize={BULK_EDIT_TABLE_MIN_SIZE}>
269→                  <BulkEditTable
270→                    onFocusNode={handleBulkEditFocusNode}
271→                    onFocusEdge={handleBulkEditFocusEdge}
272→                    highlightId={bulkEditHighlightId}
273→                    selectedIds={bulkEditSelectedIds}
274→                  />
275→                </ResizablePanel>
276→              </ResizablePanelGroup>
277→            </div>
278→          ) : (
279→          <div className="flex flex-1 overflow-hidden">
280→            <CollapsiblePanel
281→              side="left"
282→              isOpen={leftOpen}
283→              onToggle={toggleLeft}
284→              width={leftWidth}
285→              ribbonLabel="Nodes"
286→            >
287→              <NodePalette />
288→            </CollapsiblePanel>
289→
290→            <ResizablePanelGroup orientation="horizontal" className="flex-1">
291→              <ResizablePanel defaultSize={rightOpen ? 70 : 100} minSize={30}>
292→                <FlowCanvas />
293→              </ResizablePanel>
294→
295→              {rightOpen && (
296→                <>
297→                  <ToggleResizeHandle onClick={toggleRight} />
298→                  <ResizablePanel defaultSize={30} minSize={15}>
299→                    <MermaidPreview />
