  8→function hasPath(
  9→  edges: { source: string; target: string }[],
 10→  from: string | null,
 11→  to: string | null
 12→): boolean {
 13→  if (!from || !to) return false;
 14→  if (from === to) return true;
 15→  const adj = new Map<string, string[]>();
 16→  for (const e of edges) {
 17→    if (!adj.has(e.source)) adj.set(e.source, []);
 18→    adj.get(e.source)!.push(e.target);
 19→  }
 20→  const visited = new Set<string>();
 21→  const queue = [from];
 22→  while (queue.length > 0) {
 23→    const current = queue.shift()!;
 24→    if (current === to) return true;
 25→    if (visited.has(current)) continue;
 26→    visited.add(current);
 27→    for (const next of adj.get(current) ?? []) {
 28→      queue.push(next);
 29→    }
 30→  }
 31→  return false;
 32→}
