138→/* React Flow: default cursor for canvas */
139→.react-flow {
140→  cursor: default;
141→}
142→
143→/* Node body: grab cursor for dragging */
144→.react-flow .react-flow__node {
145→  cursor: grab !important;
146→}
147→.react-flow .react-flow__node:active {
148→  cursor: grabbing !important;
149→}
150→
151→/* Node label: inherit grab cursor from node (edit via double-click) */
