158→  cursor: crosshair !important;
159→}
160→
161→.react-flow .react-flow__handle {
162→  overflow: visible !important;
163→}
164→
165→.react-flow .react-flow__handle::after {
166→  content: none;
167→}
168→
169→/* Hide React Flow's default edge update anchors (reconnection is handled by ring handles) */
170→.react-flow__edgeupdater {
171→  display: none !important;
172→}
173→
174→/* Hide the original edge while reconnecting from ring handle */
175→.react-flow__edge.reconnecting {
176→  visibility: hidden;
177→}
178→
