/* React Flow: hide caret and selection everywhere */
.react-flow,
.react-flow *:not(textarea):not(input) {
  caret-color: transparent !important;
  outline: none !important;
  user-select: none !important;
}

/* React Flow: default cursor for canvas */
.react-flow {
  cursor: default;
}

/* Node body: grab cursor for dragging */
.react-flow .react-flow__node {
  cursor: grab !important;
}
.react-flow .react-flow__node:active {
  cursor: grabbing !important;
}

/* Node label: inherit grab cursor from node (edit via double-click) */
.react-flow .node-label-text {
  cursor: inherit !important;
}

/* Connection handles: crosshair cursor + expanded hit area */
.react-flow .react-flow__handle {
  cursor: crosshair !important;
}

.react-flow .react-flow__handle {
  overflow: visible !important;
}

.react-flow .react-flow__handle::after {
  content: none;
}

/* Hide React Flow's default edge update anchors (reconnection is handled by ring handles) */
.react-flow__edgeupdater {
  display: none !important;
}

/* Hide the original edge while reconnecting from ring handle */
.react-flow__edge.reconnecting {
  visibility: hidden;
}

/* Ghost node/edge (predictive input preview — always visible, very faint) */
.react-flow__node[data-id^="__ghost__"] {
  opacity: 0.15;
  cursor: pointer;
  transition: opacity 0.15s ease;
}
.react-flow__node[data-id^="__ghost__"]:hover {
  opacity: 0.4;
}
.react-flow__edge[data-id^="__ghost_edge__"] {
  opacity: 0.15;
  pointer-events: none;
  transition: opacity 0.15s ease;
}

/* Resize handles: direction-aware resize cursors */
.react-flow .react-flow__node .react-flow__resize-control.left,
.react-flow .react-flow__node .react-flow__resize-control.line.left,
.react-flow .react-flow__node .react-flow__resize-control.right,
.react-flow .react-flow__node .react-flow__resize-control.line.right {
  cursor: ew-resize !important;
}
.react-flow .react-flow__node .react-flow__resize-control.top,
.react-flow .react-flow__node .react-flow__resize-control.line.top,
.react-flow .react-flow__node .react-flow__resize-control.bottom,
.react-flow .react-flow__node .react-flow__resize-control.line.bottom {
  cursor: ns-resize !important;
}
.react-flow .react-flow__node .react-flow__resize-control.top.left,
.react-flow .react-flow__node .react-flow__resize-control.bottom.right {
  cursor: nwse-resize !important;
}
.react-flow .react-flow__node .react-flow__resize-control.bottom.left,
.react-flow .react-flow__node .react-flow__resize-control.top.right {
  cursor: nesw-resize !important;
